// Clean up initial summary for downstream use
// This content feeds directly into prompt_perso_prof AND gets inserted to SB later
const summaryRaw = $('Initial_summary1').first().json.text || '';
const reportId = $('Process Survey Data1').first().json.report_id;

// Clean markdown formatting, convert to HTML (same logic as original)
let content = summaryRaw
  .replace(/###\s*\*\*([^*]+)\*\*/g, '<h5>$1</h5>')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\*([^*]+)\*/g, '$1')
  .trim();

return [{
  json: {
    report_id: reportId,
    content: content
  }
}];

// 1. MASTER SCHEMA - Maps ID to UUID and Full Question Data (STARTER survey 00000000-0000-0000-0000-000000000002)
  const SURVEY_SCHEMA = {
    // --- SECTION 1: Getting to know you ---
    "1a": { uuid: "a1a1a1a1-0001-4000-a000-000000000001", question: "Your name", type: "short_text", options: [], description: "First and last name" },
    "1b": { uuid: "a1a1a1a1-0001-4000-a000-000000000002", question: "Your age", type: "number", options: [], description: "" },
    "1c": { uuid: "a1a1a1a1-0001-4000-a000-000000000003", question: "What region are you based?", type: "dropdown", options: ["Northern and Western Europe", "Southern and Eastern Europe", "United Kingdom (London)", "United Kingdom (Other)", "United States (High-Cost Regions)", "United States (Average-Cost Regions)", "United States (Lower-Cost Regions)", "Canada", "Australia and New Zealand", "Switzerland"], description: "If you are about to move, pick the region you are moving to." },
    "1d": { uuid: "a1a1a1a1-0001-4000-a000-000000000004", question: "What's your current situation?", type: "multiple_choice", options: ["Studying full-time", "Just graduated, looking for my first serious job", "Working my first job, wondering if it's the right one", "Working a job I want out of", "Taking a gap or in-between period"], description: "" },
