    "3b": { uuid: "a1a1a1a1-0003-4000-a000-000000000002", question: "A year into your first serious job, what would make you say 'this was a win'?", type: "long_text", options: [], description: "" },
    "3c": { uuid: "a1a1a1a1-0003-4000-a000-000000000003", question: "Where's your head at with the job market right now?", type: "multiple_choice", options: ["Honestly anxious, it feels stacked against my generation", "Frustrated, I do everything right and get nowhere", "Neutral, it is what it is", "Optimistic, I'll find my way", "I haven't really thought about it"], description: "" },
    "3d": { uuid: "a1a1a1a1-0003-4000-a000-000000000004", question: "And AI? How do you feel about it and work?", type: "multiple_choice", options: ["Worried it will eat the jobs I'm aiming for", "Confused about what it means for me", "Curious, I want to use it to get ahead", "I already use it daily", "Indifferent"], description: "" },
    "3e": { uuid: "a1a1a1a1-0003-4000-a000-000000000005", question: "What's your biggest worry about starting your career?", type: "long_text", options: [], description: "" },

    // --- SECTION 4: Interests and strengths ---
    "4a": { uuid: "a1a1a1a1-0004-4000-a000-000000000001", question: "Which subjects did you actually enjoy in school or your studies?", type: "short_text", options: [], description: "The ones they would pick again." },
    "4b": { uuid: "a1a1a1a1-0004-4000-a000-000000000002", question: "What do friends or classmates come to you for?", type: "long_text", options: [], description: "The thing people naturally ask their help with." },
    "4c": { uuid: "a1a1a1a1-0004-4000-a000-000000000003", question: "What's the thing you're most proud of making, doing, or organizing?", type: "long_text", options: [], description: "A school project, a shift they ran, something built or posted online, an event, a personal record." },
    "4d": { uuid: "a1a1a1a1-0004-4000-a000-000000000004", question: "List personal interests or hobbies that matter to you", type: "interests_hobbies", options: [], description: "Up to 3 (e.g. gaming, football, thrifting, cooking, editing videos, sneakers, reading...)" },
    "4e": { uuid: "a1a1a1a1-0004-4000-a000-000000000005", question: "How are you with technology?", type: "multiple_choice", options: ["I can make tech do things most people can't (coding, editing, automating)", "I learn any new tool fast", "I'm fine with everyday apps and tools", "I prefer to keep tech simple"], description: "" },
    "4f": { uuid: "a1a1a1a1-0004-4000-a000-000000000006", question: "Which of these sound most like you?", type: "multiple_choice", options: ["Making or building things", "Analyzing and figuring things out", "Helping or teaching people", "Selling or convincing", "Organizing and planning", "Creating content or design", "Working with my hands", "Working with numbers", "Caring for people or animals", "Being outdoors and on the move"], description: "Pick 2 to 4." },

